1→#include "source/common/listener_manager/active_tcp_socket.h"
     2→
     3→#include "envoy/network/filter.h"
     4→
     5→#include "source/common/listener_manager/active_stream_listener_base.h"
     6→#include "source/common/stream_info/stream_info_impl.h"
     7→
     8→namespace Envoy {
     9→namespace Server {
    10→
    11→ActiveTcpSocket::ActiveTcpSocket(ActiveStreamListenerBase& listener,
    12→                                 Network::ConnectionSocketPtr&& socket,
    13→                                 bool hand_off_restored_destination_connections)
    14→    : listener_(listener), socket_(std::move(socket)),
    15→      hand_off_restored_destination_connections_(hand_off_restored_destination_connections),
    16→      iter_(accept_filters_.end()),
    17→      stream_info_(std::make_unique<StreamInfo::StreamInfoImpl>(
    18→          listener_.dispatcher().timeSource(), socket_->connectionInfoProviderSharedPtr(),
    19→          StreamInfo::FilterState::LifeSpan::Connection)) {
    20→  listener_.stats_.downstream_pre_cx_active_.inc();
    21→}
    22→
    23→ActiveTcpSocket::~ActiveTcpSocket() {
    24→  accept_filters_.clear();
    25→
    26→  listener_.stats_.downstream_pre_cx_active_.dec();
    27→  // If the underlying socket is no longer attached, it means that it has been transferred to
    28→  // an active connection. In this case, the active connection will decrement the number
    29→  // of listener connections.
    30→  // TODO(mattklein123): In general the way we account for the number of listener connections
    31→  // is incredibly fragile. Revisit this by potentially merging ActiveTcpSocket and
    32→  // ActiveTcpConnection, having a shared object which does accounting (but would require
    33→  // another allocation, etc.).
    34→  if (socket_ != nullptr) {
    35→    listener_.decNumConnections();
    36→  }
    37→}
    38→
    39→Event::Dispatcher& ActiveTcpSocket::dispatcher() { return listener_.dispatcher(); }
    40→
    41→void ActiveTcpSocket::onTimeout() {
    42→  listener_.stats_.downstream_pre_cx_timeout_.inc();
    43→  ASSERT(inserted());
    44→  ENVOY_LOG(debug, "listener filter times out after {} ms",
    45→            listener_.listener_filters_timeout_.count());
    46→
    47→  if (listener_.continue_on_listener_filters_timeout_) {
    48→    ENVOY_LOG(debug, "fallback to default listener filter");
    49→    newConnection();
    50→  }
    51→  unlink();
    52→}
    53→
    54→void ActiveTcpSocket::startTimer() {
    55→  if (listener_.listener_filters_timeout_.count() > 0) {
    56→    timer_ = listener_.dispatcher().createTimer([this]() -> void { onTimeout(); });
    57→    timer_->enableTimer(listener_.listener_filters_timeout_);
    58→  }
    59→}
    60→
    61→void ActiveTcpSocket::unlink() {
    62→  auto removed = listener_.removeSocket(std::move(*this));
    63→  if (removed->timer_ != nullptr) {
    64→    removed->timer_->disableTimer();
    65→  }
