void ActiveTcpSocket::createListenerFilterBuffer() {
  listener_filter_buffer_ = std::make_unique<Network::ListenerFilterBufferImpl>(
      socket_->ioHandle(), listener_.dispatcher(),
      [this](bool error) {
        socket_->ioHandle().close();
