   444→void ConnectionManagerImpl::handleCodecErrorImpl(absl::string_view error, absl::string_view details,
   445→                                                 StreamInfo::CoreResponseFlag response_flag) {
   446→  ENVOY_CONN_LOG(debug, "dispatch error: {}", read_callbacks_->connection(), error);
   447→  read_callbacks_->connection().streamInfo().setResponseFlag(response_flag);
   448→
   449→  // HTTP/1.1 codec has already sent a 400 response if possible. HTTP/2 codec has already sent
   450→  // GOAWAY.
   451→  doConnectionClose(Network::ConnectionCloseType::FlushWriteAndDelay, response_flag, details);
